def gen(rng, size):
    n = max(1, size)
    out = []
    depth = 0
    for _ in range(n):
        if depth > 0 and rng.random() < 0.4:
            out.append('*')
            depth -= 1
        else:
            out.append(rng.choice('abcdefghijklmnopqrstuvwxyz'))
            depth += 1
    return [''.join(out)]

