class Solution:
    def removeStars(self, s):
        chars = list(s)
        i = 0
        while i < len(chars):
            if chars[i] == '*':
                j = i - 1
                while chars[j] == '#':
                    j -= 1
                chars[j] = '#'
                chars[i] = '#'
            i += 1
        return ''.join(c for c in chars if c != '#')

